static void error_diccionario(const char *nom) {
    perror(nom);
    exit(1);
}

static int16_t leer_i16_le(FILE *f, const char *nom) {
    uint8_t b[2];
    if (fread(b, 1, 2, f) != 2) {
        error_diccionario(nom);
    }
    return (int16_t)((uint16_t)b[0] | ((uint16_t)b[1] << 8));
}

static int32_t leer_i32_le(FILE *f, const char *nom) {
    uint8_t b[4];
    if (fread(b, 1, 4, f) != 4) {
        error_diccionario(nom);
    }
    return (int32_t)((uint32_t)b[0] |
                     ((uint32_t)b[1] << 8) |
                     ((uint32_t)b[2] << 16) |
                     ((uint32_t)b[3] << 24));
}

static void leer_bytes(FILE *f, void *buf, size_t n, const char *nom) {
    if (n > 0 && fread(buf, 1, n, f) != n) {
        error_diccionario(nom);
    }
}

int main(int argc, char **argv) {
    if (argc != 3) {
        uso();
    }

    const char *nom = argv[1];
    const char *llave_busqueda = argv[2];

    FILE *dicc = fopen(nom, "rb");
    if (dicc == NULL) {
        perror(nom);
        return 1;
    }

    int32_t pos = 0;
    while (pos != -1) {
        if (fseek(dicc, pos, SEEK_SET) != 0) {
            error_diccionario(nom);
        }

        int32_t izq = leer_i32_le(dicc, nom);
        int32_t der = leer_i32_le(dicc, nom);
        int16_t tam_llave = leer_i16_le(dicc, nom);
        int16_t tam_valor = leer_i16_le(dicc, nom);

        if (tam_llave < 0 || tam_valor < 0) {
            error_diccionario(nom);
        }

        char *llave = malloc((size_t)tam_llave + 1);
        if (llave == NULL) {
            error_diccionario(nom);
        }
        leer_bytes(dicc, llave, (size_t)tam_llave, nom);
        llave[tam_llave] = '\0';

        int cmp = strcmp(llave_busqueda, llave);
        if (cmp == 0) {
            char *valor = malloc((size_t)tam_valor + 1);
            if (valor == NULL) {
                free(llave);
                error_diccionario(nom);
            }
            leer_bytes(dicc, valor, (size_t)tam_valor, nom);
            valor[tam_valor] = '\0';
            printf("%s\n", valor);
            free(valor);
            free(llave);
            fclose(dicc);
            return 0;
        }

        free(llave);
        pos = (cmp < 0) ? izq : der;
    }

    fprintf(stderr, "La llave %s no existe\n", llave_busqueda);
    fclose(dicc);
    return 1;
}

